function safeParseJSON(content) {
  if (!content) return {};
  var cleaned = content.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  try { return JSON.parse(cleaned); } catch(e) { return { _raw: String(content).substring(0, 200) }; }
}
var webhook = $('Webhook').item.json.body || {};
var token = $('Create Review Token').item.json.token;
var baseUrl = $env.LEAD_REVIEW_BASE_URL;
var researchContent = $('Company Research (LLM)').item.json.choices[0].message.content;
var analysisContent = $('AI Lead Analysis (LLM)').item.json.choices[0].message.content;
var draftContent = $('Generate Email Draft (LLM)').item.json.choices[0].message.content;
var research = safeParseJSON(researchContent);
var analysis = safeParseJSON(analysisContent);
var draft = safeParseJSON(draftContent);
var convStarters = analysis.conversation_starters || [];
var questions = analysis.questions || [];
return [{
  json: {
    first_name: webhook.firstName || '',
    last_name: webhook.lastName || '',
    email: webhook.email || '',
    company_name: webhook.company_name || 'N/A',
    service_area: webhook.service || '',
    phone: webhook.phone || 'N/A',
    review_url: baseUrl + '/' + token,
    research_summary: research.summary || 'N/A',
    research_industry: research.industry || 'N/A',
    research_size: research.size || 'N/A',
    research_funding: research.funding_stage || 'N/A',
    research_products: research.key_products || 'N/A',
    research_news: research.recent_news || 'N/A',
    analysis_summary: analysis.summary || 'N/A',
    analysis_approach: analysis.approach || 'N/A',
    analysis_starters: convStarters.slice(0,3).join(' | ') || 'N/A',
    analysis_questions: questions.slice(0,3).join(' | ') || 'N/A',
    draft_subject: draft.subject || 'New Lead',
    draft_body: draft.body_text || draft.body || 'N/A'
  }
}];

